def is_armstrong_number(num):
    # Convert the number to a string to iterate through digits
    digits = str(num)
    power = len(digits)
    total_sum = 0

    for digit in digits:
        # Calculate the power of each digit
        total_sum += int(digit) ** power

    # Utilize a conditional statement to check if the sum equals the original number
    if total_sum == num:
        return True
    else:
        return False

